import{_ as t,o as i,c as n,ae as r}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"OpenSIN-Bridge Monetization","description":"","frontmatter":{},"headers":[],"relativePath":"bridges/opensin-bridge-monetization.md","filePath":"bridges/opensin-bridge-monetization.md"}'),a={name:"bridges/opensin-bridge-monetization.md"};function o(s,e,l,c,d,h){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="opensin-bridge-monetization" tabindex="-1">OpenSIN-Bridge Monetization <a class="header-anchor" href="#opensin-bridge-monetization" aria-label="Permalink to &quot;OpenSIN-Bridge Monetization&quot;">​</a></h1><p><strong>OpenSIN-Bridge</strong> operates on a Thin-Client / Server-Brain architecture to protect intellectual property and enforce SaaS subscriptions.</p><h2 id="pricing-model" tabindex="-1">Pricing Model <a class="header-anchor" href="#pricing-model" aria-label="Permalink to &quot;Pricing Model&quot;">​</a></h2><ul><li><strong>Free Install:</strong> Extension can be installed for free from the Chrome Web Store.</li><li><strong>OpenSIN Pro (5 EUR/month):</strong> Unlocks all autonomous capabilities (e.g., A2A-SIN-Worker-Prolific integration).</li></ul><h2 id="why-this-architecture" tabindex="-1">Why This Architecture? <a class="header-anchor" href="#why-this-architecture" aria-label="Permalink to &quot;Why This Architecture?&quot;">​</a></h2><p>Chrome Extensions are client-side JavaScript. To prevent cloning and reverse-engineering, <strong>Zero Business Logic</strong> exists in the extension. The extension is merely a DOM-extractor and action-executor. All LLM decisions, anti-detection mechanisms, and persona configurations live on our secure Cloudflare Workers backend.</p><h2 id="the-a2a-sin-stripe-integration" tabindex="-1">The A2A-SIN-Stripe Integration <a class="header-anchor" href="#the-a2a-sin-stripe-integration" aria-label="Permalink to &quot;The A2A-SIN-Stripe Integration&quot;">​</a></h2><p>Instead of handling Stripe events directly in the Cloudflare Worker, we leverage our dedicated <strong>A2A-SIN-Stripe</strong> agent.</p><ol><li>User upgrades to Pro via the extension popup -&gt; Stripe Checkout.</li><li>Stripe Webhook fires on successful payment.</li><li><strong>A2A-SIN-Stripe</strong> catches the webhook, validates the payment, and securely updates the user&#39;s subscription status in our central <strong>Supabase</strong> database.</li><li>The Cloudflare Worker validates the JWT against Supabase on every API call to ensure the user has an active Pro plan.</li></ol>',9)])])}const u=t(a,[["render",o]]);export{g as __pageData,u as default};
